fun solve(m: Long, n: Long, waitCost: Array<Array<Long>>): Long {
    if (m == 1L && n == 1L) {
        return 1L
    }
    val mm = m.toInt()
    val nn = n.toInt()
    val INF = 1e18.toLong()
    val dp0 = Array(mm) { Array(nn) { INF } }
    val dp1 = Array(mm) { Array(nn) { INF } }
    dp1[0][0] = 1L

    for (i in 0 until mm) {
        for (j in 0 until nn) {
            if (i == 0 && j == 0) {
            } else {
                var candidate = INF
                if (j > 0) {
                    candidate = minOf(candidate, dp1[i][j-1] + (i+1).toLong() * (j+1).toLong())
                }
                if (i > 0) {
                    candidate = minOf(candidate, dp1[i-1][j] + (i+1).toLong() * (j+1).toLong())
                }
                dp0[i][j] = minOf(dp0[i][j], candidate)
            }

            if (dp0[i][j] < INF) {
                dp1[i][j] = minOf(dp1[i][j], dp0[i][j] + waitCost[i][j])
            }

            if (dp1[i][j] < INF) {
                if (j + 1 < nn) {
                    val newCost = dp1[i][j] + (i+1).toLong() * (j+2).toLong()
                    if (newCost < dp0[i][j+1]) {
                        dp0[i][j+1] = newCost
                    }
                }
                if (i + 1 < mm) {
                    val newCost = dp1[i][j] + (i+2).toLong() * (j+1).toLong()
                    if (newCost < dp0[i+1][j]) {
                        dp0[i+1][j] = newCost
                    }
                }
            }
        }
    }

    return dp0[mm-1][nn-1]
}
